var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"가지 마.","JPN":"行かないで。","ENG":"Don't go.","TWN":"別去。"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"직원 한 명이 무사한지 알아보려고 북방합의체에 직접 발을 들인다니. 리스크가 너무 커.","JPN":"職員1人の無事を確認するために、北方合意体に直接侵入するなんて。リスクが大きすぎる。","ENG":"It's just too risky for you to step foot into the Northern Union to find out if one of your employees is safe.","TWN":"為了確認一名員工的安全，親自踏入北方和議會領土。這其中的風險太大了。"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"나 혼자 가는 건 아닐세. 하지만 내가 빠질 수는 없어.","JPN":"私1人で行くわけではない。だが、私が行かないわけにはいかない。","ENG":"I'm not going alone. But I must be there.","TWN":"放心，我不是一個人。而且我絕對不能缺席。"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"최고관리자가 목숨을 걸어야 할 일이라면 차라리 포기해. 고작 연락이 안 닿을 뿐인 거잖아.","JPN":"最高管理者が命をかけるほどのことなら、いっそ諦めたら。別に連絡が取れないだけじゃない。","ENG":"If it's something the Supreme Administrator has to risk his life for, then I suggest you just let it go. It's just we've lost contact with him.","TWN":"如果連最高管理者都必須拼命的事情，那還不如放棄算了。現在只是聯絡不上而已啊。"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"합의체가 관리국을 어떻게 대할지 몰라서 그러는 거야?","JPN":"合意体が管理局にどんな態度を取るのかわからないわけじゃないよね？","ENG":"You know how the Northern Union treats the Administration, right?","TWN":"你難道不知道北方和議會是怎麼對待管理局的嗎……？"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"날 걱정해주는 건가?","JPN":"私を心配してくれるのか？","ENG":"Are you worried about me?","TWN":"你是在擔心我嗎？"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"그야 당연하지!","JPN":"当たり前でしょ！","ENG":"Of course, I am!","TWN":"那當然。"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L11_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"최고관리자가 인질로 잡혔다간, 안 그래도 당신 때문에 떨어진 관리국의 체면과 신뢰가 더 바닥으로 곤두박질 칠 테니까!","JPN":"最高管理者が人質にでもなったら、ただでさえあなたのせいでガタ落ちになった管理局の面子と信頼は地の底まで落ちちゃうだろうから！","ENG":"If the Supreme Administrator is taken hostage, the Administration's reputation and credibility will crash! All because of you!","TWN":"最高管理者被劫持的話，本來就因為你而下降的管理局顏面和信譽會更加跌到谷底的！"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_HIT_SMALL"},{"id":"L13_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"직원이라고 말은 했지만, 곧 다가올 클리포트 게임에 반드시 필요한 전력일세.","JPN":"職員と言っているが、目前に迫っているクリフォトゲームに必ず必要な戦力だ。","ENG":"I said that it was an employee of mine, but she's also a key factor I need for the next Qliphoth Game.","TWN":"說是說員工，但她也是即將到來的逆卡巴拉遊戲中必不可少的戰力。"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그런 직원에게 문제가 생겼다면 무리를 해서라도 데려와야지.","JPN":"その職員に問題が起こったのなら、無理をしてでも連れてくるべきさ。","ENG":"So, if something has happened to her, I must do whatever I can to bring her back.","TWN":"如果那位員工遇到困難，就算拼命也要把她帶回來。"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"하아, 난 경고할 만큼 했어.","JPN":"はあ、私は警告したからね。","ENG":"*Sigh* I warned you.","TWN":"欸……我已經警告過了。"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"방송에 당신 피랍소식이 뜨는 순간 시니어는 때려치우고 이직할 거니까 알아서 해.","JPN":"テレビであなたの拉致ニュースが出た瞬間、シニアはやめて転職するから。もう好きにして。","ENG":"Just know that the moment I see news of your kidnapping, I'm going to quit my job as a Senior and find a different job.","TWN":"一旦你的被綁架的消息出現在新聞裡，我就會辭職跳槽，所以你自己看著辦吧。"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그런 일은 없도록 조심하지.","JPN":"そうならないように気をつけるさ。","ENG":"I'll be careful not to let that happen.","TWN":"我會小心，不會讓那種事發生的。"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그럼 다녀오겠네.","JPN":"では、行ってくるよ。","ENG":"Then, I'll be back before you know it.","TWN":"那我走了。"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"잠깐.","JPN":"待って。","ENG":"Wait.","TWN":"等一下。"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"음?","JPN":"うむ？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"내 연락책도 한 명 데려가.","JPN":"私の連絡役も1人連れて行って。","ENG":"Take one of my contacts with you too.","TWN":"帶上我的聯絡人。"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"당신이 뭘 하고 돌아다니는 건지, 시니어인 나에게도 알 권리가 있으니까.","JPN":"あなたが何をしながら歩き回ってるのか、シニアの私にも知る権利があるからね。","ENG":"I have a right to know what you are up to as a Senior.","TWN":"你在外面做什麼，我作為Senior也有權知道。"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"연락책?","JPN":"連絡役？","ENG":"Contact?","TWN":"聯絡人？"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NONAME","text":{"KOREA":"정식으로 인사드리죠.","JPN":"正式にご挨拶申し上げます。","ENG":"Pleased to meet you, sir.","TWN":"正式向你問好。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NONAME","text":{"KOREA":"로터스 경호국장 파티마입니다. 최고관리자님의 호위를 맡게 되어 영광입니다.","JPN":"ロータスの警護局長、ファティマです。最高管理者様の護衛を担当することになり、光栄です。","ENG":"I am Fatima, Chief of Lotus' security. It is an honor to serve as your bodyguard.","TWN":"我是洛德斯警衛局的局長，法蒂瑪。能夠擔任最高管理者的保鑣是我的榮幸。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"편하게, 파티마라고 불러주십시오.","JPN":"ファティマとお呼びください。","ENG":"Please feel free to address me as Fatima.","TWN":"請叫我法蒂瑪就好。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L34_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"합의체와의 마찰을 피하기 위해 관리국 인원은 쓰지 않기로 한 거 아니었나?","JPN":"合意体とのもめごとを避けるために、管理局の人員を使わないことにしたわけではなかったのか？","ENG":"Didn't you say you didn't want to use any of the Administration's personnel to avoid any conflict with the Northern Union?","TWN":"不是說為了避免與北方和議會發生衝突，不使用管理局的人嗎？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"이미 최고관리자가 그 영토에 발을 들이기로 한 마당에 그런 게 무슨 의미가 있겠어?","JPN":"すでに最高管理者がその領土に足を踏み入れると決めた今、そんなことに何の意味がある？","ENG":"That's been thrown out the window when the Supreme Administrator said that he'd go there himself.","TWN":"你這個最高管理者都已經自己去了，現在說這些還有什麼意義？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"일부러 합의체 녀석들 눈에 띄지만 마.","JPN":"合意体のやつらの目につかないようにしてよ。","ENG":"Just don't try to get their attention, okay?","TWN":"別故意引起那幫人的注意，好嗎？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네 수행원을 데려가도 괜찮은 건가? 스완이 언제 자넬 노리러 올 지 모르는데.","JPN":"君の随行員を連れて行ってもいいのかね？　スワンがいつ君を狙ってくるかわからないんだぞ。","ENG":"Is it okay for me to take your bodyguard with me? What if Swan comes after you?","TWN":"但把你的屬下帶走沒問題嗎？不知道史旺會不會找過來？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"괜찮아. 스완이 진짜로 나타나면 원하는 정보 다 넘겨주고 싹싹 빌 거니까.","JPN":"大丈夫だよ。スワンが現われたら、要求する情報を全部渡して命乞いするから。","ENG":"It's fine. If Swan really does come for me, then I'll give her all the information she wants and beg for my life.","TWN":"沒關係。如果她真的出現，我會老實交代，然後乖乖求饒的。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L41_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"뭐가 됐든 당신이 붙잡히는 것보단 낫겠지. 안 그래?","JPN":"とにかく、あなたが捕まるよりはましでしょ。違う？","ENG":"Whatever the case, it's far better than you getting caught, isn't it?","TWN":"不管怎麼樣，總比你被抓住好吧？不是嗎？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L44_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"난 바쁘니까 작업실로 들어가겠어.","JPN":"私は忙しいから、作業室に戻るよ。","ENG":"I'm busy, so I have to get back to my lab.","TWN":"我很忙，先回工作室了。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"최고관리자가 허튼짓하면 핫라인으로 보고해, 파티마.","JPN":"最高管理者が余計なことをしたらホットラインで報告して、ファティマ。","ENG":"Fatima, if the Supreme Administrator does anything stupid, report it through the hotline.","TWN":"如果最高管理者亂來，就立刻通知我，法蒂瑪。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"알겠습니다.","JPN":"承知しました。","ENG":"Understood.","TWN":"是。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그렇게 노려보면 무서운데.","JPN":"そうやって睨まれると怖いのだが。","ENG":"It's intimidating when you glare at me like that.","TWN":"……你這樣盯著我有點可怕。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"여기에 사인 부탁드립니다.","JPN":"ここにサインをお願いします。","ENG":"Please sign here.","TWN":"請在這裡簽字。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L2_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그러지.","JPN":"わかった。","ENG":"Very well.","TWN":"好、好的。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그런데, 이 종이엔 조항이 적혀있진 않군. 뭘 위한 사인이지?","JPN":"ところで、この紙には何も書かれていないが。何のためのサインだ？","ENG":"I've noticed that there aren't any clauses written on this document. Why did you need my signature?","TWN":"可是，這張紙上沒寫內容。是為什麼要簽名？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"개인 소장용입니다.","JPN":"個人用です。","ENG":"For my personal collection.","TWN":"個人收藏用。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그… 렇군.","JPN":"そう……か。","ENG":"I... see.","TWN":"我……明白了。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"교통편은 정하셨습니까?","JPN":"交通手段は決めたのですか？","ENG":"Have you decided on your mode of transportation?","TWN":"交通方式你有確定了嗎?"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"차원함선으로 이동하는 게 가장 편하겠지만…","JPN":"次元艦船で移動するのが一番便利だろうが……","ENG":"It would be best to travel by dimensional ship, but...","TWN":"雖然乘坐次元艦船是最方便的……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"눈에 띄지 않도록 경비행기로 이동하지.","JPN":"目立たないように軽飛行機で移動しよう。","ENG":"Let's take a light aircraft to avoid garnering any unwanted attention.","TWN":"為了不引人注目，還是改用輕型飛機移動吧。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"뭐…?","JPN":"は……？","ENG":"What...?","TWN":"什麼……？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"그런 일이 있는 거면 나도 데려가야지!","JPN":"そんなことがあったなら、私も連れて行くべきだよ！","ENG":"If something like that has happened, then you should've taken me as well!","TWN":"如果有這樣的事，那也得帶上我吧？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"사장님 말은 지금 소대장이 위험에 처했을지도 모른단 거잖아!","JPN":"今の話、小隊長が危険かもしれないってことでしょ！","ENG":"What you're telling me is that our Division Commander might be in danger, Boss!","TWN":"老闆你的意思是現在小隊長可能也陷入危險之中！？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"최악의 상황을 가정한다면 그렇지.","JPN":"最悪の状況を想定するならそうなるな。","ENG":"That is, only if you assume the worst.","TWN":"我只是先假設最糟糕的情況。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L20_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 미나 양이 걱정하는 것처럼 힐데 소대장이 그리 쉽게 위험에 빠지진 않을 걸세.","JPN":"だが、ミナ君が心配しているように、ヒルデ小隊長がそう簡単にピンチに陥ることはない。","ENG":"But don't worry, Mina. Commander Hilde won't fall into danger so easily.","TWN":"不過，希爾德小隊長不會像米娜擔心的那樣輕易陷入危險的。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"어…?","JPN":"え……？","ENG":"Huh...?","TWN":"呃……？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"으음… 소대장에게 위기라니. 별로 상상이 안되긴 하네.","JPN":"うーん……小隊長がピンチって。あまり想像がつかないね。","ENG":"Mm... Commander in danger? It is hard to imagine.","TWN":"嗯……小隊長會遇到危機，確實難以想像啊。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"연락두절은 단순한 기기 문제일 가능성이 높지. 연락이 두절된 곳은 침식파가 짙은 균열 근처니까.","JPN":"連絡が途絶えたのは単なる機器の問題である可能性が高い。連絡が途切れた場所は侵食波が濃い亀裂の周辺だからな。","ENG":"It's more likely that we can't contact her due to a simple device issue, since we lost contact near a Crevice with dense Corruption rays.","TWN":"聯絡中斷很可能只是設備問題。畢竟失聯地點在侵蝕波強烈的峽谷附近。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"어디까지나 확인 차 가는 것이니, 미나 양은 다음 작전까지 회복에 전념해주게.","JPN":"あくまで確認のために行くのだから、ミナ君は次の作戦まで回復に専念してくれたまえ。","ENG":"I'm just going there to check. So Mina, you should focus on your recovery until your next mission.","TWN":"我只是去確認一下，米娜請專心修好，準備好下次作戰。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"퇴원 예정일까진 돌아올 테니, 그때 다 같이 식사나 하지.","JPN":"退院の予定日までには戻るから、その時にはみんなで食事でもしよう。","ENG":"I'll be back before your scheduled discharge, so let's have dinner together then.","TWN":"出院前我會回來的，到時候大家再一起吃個飯吧。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"뭐야. 불길한 복선 깔듯이 말하고 있어.","JPN":"何だよ。不吉なフラグ立てないでくれる？","ENG":"Huh? That sounds like some ominous foreshadowing.","TWN":"什麼啊，說得讓人心裡怪不安的。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"모르는 건가? 요즘 대세는 클리셰 비틀기라네.","JPN":"知らないのかね？　最近はクリシェを壊すことがトレンドなんだ。","ENG":"Didn't you know? It's a trend to put a twist on cliches these days.","TWN":"呵呵……這你就不知道了吧？最近流行講反話。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"휴우… 그럼 이것만 약속해줘.","JPN":"ふう……じゃあ、これだけは約束して。","ENG":"*Sigh* ...Then promise me this.","TWN":"呼……那就答應我這件事吧。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"정말 큰 문제가 생기면 나한테도 연락해주는 걸로.","JPN":"本当に大問題が発生したら、私にも連絡してくれるって。","ENG":"That you'll call me if something really big happens.","TWN":"如果真的出了問題，記得聯絡我。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"위기의 순간에 미나 양이 등장해줄 거라는 복선인가?","JPN":"ピンチの瞬間にミナ君が登場してくれるという伏線か？","ENG":"Is this also a foreshadowing that you'll come to save me in a moment of crisis, Mina?","TWN":"意思是危機時刻米娜會登場的伏筆嗎？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"그 복선이 실현되는 일은 없길 바랄게.","JPN":"その伏線が実現されないことを祈るよ。","ENG":"I hope it doesn't come true.","TWN":"我希望不會有這種時候。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"조심히 다녀와.","JPN":"気をつけて行ってらっしゃい。","ENG":"Be safe out there.","TWN":"路上小心……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"최고관리자님, 출발 준비를 마쳤습니다.","JPN":"最高管理者様、出発の準備が整いました。","ENG":"Supreme Administrator, we are ready to depart.","TWN":"最高管理者，都準備好了，可以出發了。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"지금 바로 가겠네.","JPN":"今すぐ行く。","ENG":"I'll be right there.","TWN":"來了。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네도 준비 됐나?","JPN":"君も準備はできたのか？","ENG":"Are you ready as well?","TWN":"你也準備好了吧？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"읏차-","JPN":"よいしょっとー","ENG":"Hup!","TWN":"嘿咻——！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"}}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_10"},{"id":"L45_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"필요한 건 다 실어 나른 것 같은데… 혹시 그 준비가 마음의 준비인가요?","JPN":"必要なものは運び終わったと思うんですけど……もしかしてその準備って、心の準備のことですか？","ENG":"I think I brought everything I need... Or were you talking about mental preparation?","TWN":"需要的東西好像都搬完了……或者你指的是心理準備嗎？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"적진 한복판에 뛰어드는 거라면 자주 해봤으니 괜찮아요.","JPN":"敵陣の真ん中に飛び込むことなら何度もやってますから、大丈夫ですよ。","ENG":"I have plenty of experience jumping into the middle of enemy territory, so I'm good.","TWN":"衝進敵營這種事我經常做的，現在已經沒問題了。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"긍정적이라서 다행이군. 이력서에선 본인 실력을 꽤나 저평가하고 있는 것 같던데 말이야.","JPN":"前向きで何よりだ。履歴書では自分の実力をかなり低評価しているように見えたがな。","ENG":"I'm glad you have a positive outlook on this. It seemed that you undervalued your skills on your resume.","TWN":"嗯，很積極嘛。你的履歷上倒是有點低估自己了。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"지휘관이 여러 번 바뀌는 걸 보면서, 자아가 너무 충만하면 명이 단축된다는 걸 배웠거든요.","JPN":"何度も指揮官が変わるのを見て、自我が強すぎると命が短くなるってことを覚えたんです。","ENG":"That's because I learned that lifespans shorten with an inflated ego after going through several commanders replaced.","TWN":"因為自我意識太強反而活不長……這是我跟了好幾任指揮官明白的道理……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L50_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"하지만 이번 작전은 무려 관리국 공인의 S급 카운터가 동행하는 거잖아요. 저 같은 사람도 긍정적일 수 밖에 없죠.","JPN":"でも今回の作戦は管理局公認S級カウンターが同行するんでしょう？　私みたいな人もポジティブになります。","ENG":"But there is an Administration confirmed Grade S Counter with us on this operation. So, even someone like me can stay positive.","TWN":"不過這次作戰可是有管理局公認的S級制裁者同行……像我這樣的人也可以樂觀點吧……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L2_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그것도 그렇군.","JPN":"それもそうだな。","ENG":"That's also true.","TWN":"說的也是。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그 이졸데라는 사람. 성격이 별나다고 하셔서 걱정했는데, 엄청 협조적이라 다행이네요.","JPN":"あのイゾルデって人。性格が変わってるって言うから心配したんですけど、すごく協力的でよかったですね。","ENG":"This Isolde person. I was worried because you said she had a quirky personality, but I'm glad she was cooperative in the end.","TWN":"那個叫伊索德的人。聽說性格很古怪，我還很擔心呢……結果這麼合作，真是太好了。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"멀리서 봤을 땐 생각보다 젊어 보이던데, 그 나이에 관리국의 시니어까지 올랐다는 게 대단하기도 하고요.","JPN":"遠から見た時は思ったより若く見えたんですけど、あの年で管理局のシニアにまでなったのはすごいことですし。","ENG":"She looked young from afar, and I think it's amazing that she became a Senior of the Administration at such a young age.","TWN":"她看起來遠比想像中年輕，能在那個年紀就升到Senior，真是了不起。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이졸데 양은 호기심 뿐만 아니라 인정 욕구도 제법 강하거든.","JPN":"イゾルデ君は好奇心だけではなく、承認欲求もなかなか強いからな。","ENG":"Isolde is not only curious, but also has a strong desire for recognition.","TWN":"她不僅好奇心強，認同慾也很強。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"일반 연구원이 아니라 시니어 직책을 제시한다면 절대 거절하지 못할 거라 생각했지.","JPN":"一般の研究員ではないシニアを提案すれば、絶対拒絶できないと思っていた。","ENG":"I thought she wouldn't be able to refuse if I offered her a Senior position instead of a regular researcher.","TWN":"如果只是給她普通研究員的職位，我想她絕對是會拒絕的。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"만일 그녀가 예정대로 퓨처앳워에서 온전히 연구에만 전념했다면, 이미 역설계를 통해 관리국과 엇비슷한 수준의 이터니움 드라이브를 자체적으로 개발해냈을지도 모르니 말이야.","JPN":"もし彼女が予定どおりにフューチャーアットウォーで研究にだけ専念していたなら、すでに逆設計によって管理局と同じくらいのエタニウムドライブを独自に開発したかもしれない。","ENG":"If she had devoted herself entirely to research at Future-at-War as she planned, she would've already developed an Eternium Drive that is competitive against the Administration's through reverse engineering.","TWN":"畢竟按照她原本的計畫，在天啟兵器專心研究的話，或許早就已經透過逆向設計自主開發出與管理局水準相當的永恆之金驅動器了。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"네…?!","JPN":"えっ……！？","ENG":"What...?!","TWN":"什麼……？！"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그 정도로 대단한 천재라면 그냥 적성에 맞는 일을 하게 두는 편이 낫지 않나요?","JPN":"そんなにすごい天才なら、適正に合った仕事をやらせた方がよかったんじゃないですか？","ENG":"Wouldn't it have been better to let a genius like her do what she's good at, then?","TWN":"如果真是那樣的天才，為什麼不讓她做適合她的工作……？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"관리국이 보유한 기술을 지금껏 은폐해 온 데엔 그럴 만한 사정이 있다네.","JPN":"管理局が保有している技術を今まで隠ぺいしてきたことは、それなりの事情があるんだ。","ENG":"There is a good reason why the Administration has been hiding its technology from the world.","TWN":"管理局一直隱瞞所擁有的技術是有原因的。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"간단히 말해, 시대가 허락한 수준을 넘어선 기술력을 남발하게 되면, 세계엔 정보오염이라 불리는 침식현상이 발생하거든.","JPN":"簡単に言うと、時代が許したレベルを越えた技術力を乱用すると、世界には情報汚染という侵食現象が発生する。","ENG":"Simply put, if technology goes past what the era can allow, a Counterside Effect in the form of data corruption will occur.","TWN":"簡單來說，如果濫用超越時代允許水準的技術，世界就會發生被稱為資訊污染的侵蝕現象。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"어… 그러니까 관리국은…","JPN":"えっと……だから、管理局は……","ENG":"Uh... So you mean…","TWN":"呃……所以管理局是……"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"세상이 침식되는 걸 막으려고 이졸데 씨를 시니어라는 직책에 가뒀다는 거죠?","JPN":"世界が侵食されることを防ぐためにイゾルデさんをシニアという役職に縛りつけたってことですよね？","ENG":"The Administration appointed Miss Isolde as a Senior to stop the world from being Corrupted?","TWN":"為了阻止世界被侵蝕……才把伊索德困在Senior的職位上，對吧……？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그녀가 시니어로서의 재능이 없다는 뜻은 아니지만, 요약하면 그렇게 되겠군.","JPN":"彼女にシニアとしての才能がないというわけではないが、要するにそうなるな。","ENG":"That's not to say that she's not capable of being a Senior, but yes, that's what it boils down to.","TWN":"這並不是說她沒有作為管理者的才能，但總結起來就是這樣。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만, 클리포트 게임이 끝난 시점에서 정보오염을 걱정할 필요가 없어졌어.","JPN":"だが、クリフォトゲームが終わった時点で情報汚染を心配する必要がなくなった。","ENG":"However, with the end of the Qliphoth Game, there is no need to worry about data corruption.","TWN":"不過，在逆卡巴拉遊戲結束之後，就不需要擔心這個問題了。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그러니 이제부터라도 그녀의 재능을 마음껏 발휘할 기회를 줄 생각이라네.","JPN":"だから、今からでも彼女の才能を存分に発揮するチャンスを与えてやるつもりだ。","ENG":"So now, I'm planning on giving her an opportunity to show off her talents to the fullest.","TWN":"所以我打算從現在起給她一個盡情發揮才能的機會。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"흐흐… 으흐흐…","JPN":"ふふ……うふふ……","ENG":"Hehe... Hehehe...","TWN":"呵呵…… 呵呵呵……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"이 잘 빠진 곡선 좀 봐. 분명 안쪽은 더 아름답겠지?","JPN":"この綺麗に窪んだ曲線を見て。きっと中はもっと美しいよね。","ENG":"Look at those curves. I'm sure the inside is even more beautiful, right?","TWN":"看看這優美的曲線。裡面一定更漂亮吧？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"망할 잔업 때문에 함선 연구는 엄두도 못 내고 있었는데, 무려 이터니움 드라이브라니. 이런 걸 만져보는 게 얼마만이람.","JPN":"ムカつく残業のせいで艦船の研究なんてとてもできなかったけど、エタニウムドライブなんて。これを触れるなんていつぶりなんだろう？","ENG":"I didn't dare think about doing ship research because of all the work I had piled up. But it's an Eternium Drive! It's been so long since I got to lay my hands on something like this.","TWN":"因為加班都根本沒時間研究艦船。這可是永恆之金驅動器耶……！好久沒接手這種東西了。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L28_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"자아, 지금부터 이 언니가 마구마구 뜯어서 분석해줄게-!","JPN":"さて、今からこのお姉さんがバンバン取り外して分析してあげるよ～！","ENG":"Okay. I'll be gentle and tear you down and analyze you!","TWN":"好啦，從現在開始，姊姊會把你好好地拆開看看～！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L30_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아 참. 그리고…","JPN":"あ、そうだ。それから……","ENG":"Oh, right. And–","TWN":"啊，對了，還有……"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"힉?! 깜짝이야!","JPN":"ひっ！？　びっくりした！","ENG":"WHOA! Geez!","TWN":"唔？！嚇了我一跳！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L32_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"뭐, 뭐야? 이 통신기가 언제부터 켜져 있었지?","JPN":"な、何？　この通信機、いつからオンになってたんだ？","ENG":"W-what? Since when was the comms on?","TWN":"什、什麼啊？這個通訊器什麼時候開著的？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"왜 그러지? 들려선 안될 얘기라도 하고 있었나?","JPN":"どうした？　聞こえてはいけない話でもしていたのかね？","ENG":"What's wrong? Were you saying something I wasn't supposed to hear?","TWN":"怎麼了？是在說不該讓我聽的話嗎？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"크윽…!","JPN":"ううっ……！","ENG":"Errgh...!","TWN":"呃……！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"빨리 떠나기나 할 것이지 용건이 뭔데!","JPN":"早く出発しなさいよ、何連絡してるの！？","ENG":"Why don't you just leave already?! What's it now?!","TWN":"你不是已經走了嗎！有什麼事快說！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이 통신기를 제외하면 나에겐 쓸만한 장비가 별로 없어서 말이지.","JPN":"この通信機を除いたら、私には使えそうな装備があまりないのだよ。","ENG":"Other than this comms device, I have no useful gear.","TWN":"除了這個通訊器，我沒什麼像樣的裝備了。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"필요해지면 자네한테 연락해서 원격으로 지원을 받고 싶은데, 괜찮겠나?","JPN":"必要になったら君に連絡して遠隔支援を頼みたいのだが、いいかね？","ENG":"So, I wanted to contact you and ask for remote support when I needed it. Is that all right?","TWN":"如果需要的話，我想聯絡你提供遠端支援，可以嗎？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"…내 도움…?","JPN":"……私の支援……？","ENG":"...You want my help...?","TWN":"你要……我來幫忙……？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"맘대로 해. 방해되는 것도 아니니까.","JPN":"好きにしたら。邪魔になるわけでもないし。","ENG":"It's fine. It won't bother me.","TWN":"隨你的便。反正也不會礙事。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"…흥, 혼자서는 다 해결할 자신이 없단 거지?","JPN":"……フン、1人では解決する自信がないってこと？","ENG":"...Hmph. So, you're saying that you're not confident in handling it on your own, eh?","TWN":"……哼，自己一個人解決不了嗎？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"알고 보니 최고관리자란 것도 별 거 없네. 그냥 평범한 사람이잖아?","JPN":"最高管理者っていっても大したことないね。ただの普通の人間だし。","ENG":"Guess the Supreme Administrator isn't such a big shot after all. He's just an ordinary person.","TWN":"原來最高管理者也沒什麼特別的嘛。只是個普通人而已？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"그럼 난, 오랜만에 손 좀 풀어볼까나-?","JPN":"さて、私は久々にちょっと実力発揮してみようかな～？","ENG":"Okay then. I guess it's time I flexed my muscles.","TWN":"那麼，我就久違地活動活動吧-？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};